module counter_4bit (
  input clk,
  input enable,
  output [4:0] count
);
  reg [4:0] counter;
  always @(posedge clk) begin
    if (enable) counter <= counter + 1;
  end
  assign count = counter;
endmodule

module timer (
  input clock,
  input start,
  output [3:0] timer_out
);
  counter_4bit cnt (
    .clk(clock),
    .enable(start),
    .count(timer_out)
  );
endmodule

